[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _sut = null!;

    [TestInitialize]
    public void Setup() => _sut = new ShoppingCart();

    // ── AddItem ────────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_AppearsInTotal()
    {
        _sut.AddItem("SKU-1", 2, 10.00m);

        Assert.AreEqual(20.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_TotalSumsAll()
    {
        _sut.AddItem("A", 1, 5.00m);
        _sut.AddItem("B", 3, 2.00m);

        Assert.AreEqual(11.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_DuplicateSku_QuantityIsAccumulated()
    {
        _sut.AddItem("SKU-1", 1, 10.00m);
        _sut.AddItem("SKU-1", 2, 10.00m);

        // 3 × 10 = 30
        Assert.AreEqual(30.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void AddItem_NullOrWhiteSpaceSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.AddItem(sku!, 1, 5.00m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddItem_InvalidQuantity_Throws(int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.AddItem("SKU-1", quantity, 5.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.AddItem("SKU-1", 1, -1.00m));
    }

    [TestMethod]
    public void AddItem_ZeroPrice_Succeeds()
    {
        _sut.AddItem("FREE", 1, 0.00m);

        Assert.AreEqual(0.00m, _sut.CalculateTotal());
    }

    // ── RemoveItem ─────────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromTotal()
    {
        _sut.AddItem("A", 1, 10.00m);
        _sut.AddItem("B", 1, 20.00m);

        _sut.RemoveItem("A");

        Assert.AreEqual(20.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsKeyNotFoundException()
    {
        Assert.ThrowsException<KeyNotFoundException>(
            () => _sut.RemoveItem("MISSING"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void RemoveItem_NullOrWhiteSpaceSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.RemoveItem(sku!));
    }

    // ── CalculateTotal ─────────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAllItemsRemoved_ReturnsZero()
    {
        _sut.AddItem("A", 1, 10.00m);
        _sut.RemoveItem("A");

        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    // ── ApplyCoupon ────────────────────────────────────────────

    [TestMethod]
    [DataRow("SAVE10", 10)]
    [DataRow("SAVE20", 20)]
    [DataRow("HALF",   50)]
    public void ApplyCoupon_ValidCode_AppliesDiscount(string code, int discountPercent)
    {
        _sut.AddItem("A", 1, 100.00m);

        _sut.ApplyCoupon(code);

        var expected = 100.00m - (100.00m * discountPercent / 100m);
        Assert.AreEqual(expected, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive_AppliesDiscount()
    {
        _sut.AddItem("A", 1, 100.00m);

        _sut.ApplyCoupon("save10");

        Assert.AreEqual(90.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void ApplyCoupon_NullOrWhiteSpaceCode_Throws(string? code)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_ReplacedBySecondCoupon_UsesLatest()
    {
        _sut.AddItem("A", 1, 100.00m);

        _sut.ApplyCoupon("SAVE10");
        _sut.ApplyCoupon("SAVE20");

        Assert.AreEqual(80.00m, _sut.CalculateTotal());
    }

    // ── Combined scenarios ─────────────────────────────────────

    [TestMethod]
    public void FullWorkflow_AddRemoveCouponTotal_ProducesCorrectResult()
    {
        _sut.AddItem("WIDGET", 2, 25.00m);  // 50
        _sut.AddItem("GADGET", 1, 30.00m);  // 30
        _sut.RemoveItem("GADGET");           // -30
        _sut.ApplyCoupon("SAVE10");          // 10% off

        // 50 − 10% = 45
        Assert.AreEqual(45.00m, _sut.CalculateTotal());
    }
}
"}

